import React from "react";

function Aleart(props) {
  return (
    <>
      <div className={`alert alert-${props.alert.type}`} role="alert">
        <strong>{props.alert.type}:</strong> {props.alert.msg}
      </div>
    </>
  );
}

export default Aleart;
